#!/usr/bin/env python3

# Define the building coordinates
buildings = [(2, 0), (5, 3), (2, 3)]

def is_valid(buildings):
    # Check bounds and uniqueness
    seen = set()
    for x, y in buildings:
        if not (0 <= x < 6 and 0 <= y < 6):
            return False
        if (x, y) in seen:
            return False
        seen.add((x, y))
    return True

if __name__ == "__main__":
    print("VALID" if is_valid(buildings) else "INVALID")

nests = [(1, 8), (1, 1)]
fences = [(3, 3), (5, 5)]

def guarded(nest):
    for fence in fences:
        if abs(nest[0] - fence[0]) + abs(nest[1] - fence[1]) <= 3:
            return True
    return False

if all(guarded(n) for n in nests):
    print("SAFE")
else:
    print("UNSAFE")

bread = 17

nests = [(2, 3), (1, 1)]
wells = [(6, 0)]
fences = [(2, 2)]
bakeries = [(6, 1)]

def manhattan(a, b):
    return abs(a[0] - b[0]) + abs(a[1] - b[1])

# Check conditions in order
if bread <= 0:
    print('lost')
else:
    # Dry if any bakery has no well within distance 2
    dry = False
    for bakery in bakeries:
        if not any(manhattan(bakery, well) <= 2 for well in wells):
            dry = True
            break
    if dry:
        print('dry')
    else:
        # Unsafe if any nest has no fence within distance 2
        unsafe = False
        for nest in nests:
            if not any(manhattan(nest, fence) <= 2 for fence in fences):
                unsafe = True
                break
        if unsafe:
            print('unsafe')
        else:
            print('thriving')

